select post.id, post.user_id, post.view_count, post.title, post.post_abstract, post.post_time, post.type, user.name, user.head_portrait,post.like_count from post join user on post.user_id = user.id where post.id in
#{id}
order by post.post_time desc

select post.user_id, user.name, user.head_portrait, post.id, post.view_count, post.title, post.post_abstract, post.post_time, post.type, post.like_count
from post
join user on post.user_id = user.id

    and post.delete_flag = 0

        and post.type = #{type}



            and post.post_time between #{startTime} and #{endTime}


            and post.post_time >= #{startTime}


            and post.post_time <= #{endTime}



        and (
        post.title like concat('%', #{condition}, '%')
        or post.post_txt like concat('%', #{condition}, '%')
        or post.post_abstract like concat('%', #{condition}, '%')
        or user.name like concat('%', #{condition}, '%')
        )

    and post.type!=2

order by post.like_count desc,post.view_count desc,post.post_time desc

